18	/// Testbench for the AXI4-Lite data width conversion module.
19	module tb_axi_lite_dw_converter #(
20	  /// Address width of the AXI4-Lite ports.
21	  parameter int unsigned TbAxiAddrWidth    = 32'd32,
22	  /// Data Width of the slave port.
23	  parameter int unsigned TbAxiDataWidthSlv = 32'd32,
24	  /// Data Width of the master port.
25	  parameter int unsigned TbAxiDataWidthMst = 32'd128,
26	  /// Number of write transactions.
27	  parameter int unsigned NumWrites         = 32'd10000,
28	  /// Number of read tranactions.
29	  parameter int unsigned NumReads          = 32'd10000
30	);
31	  // Random master no Transactions
32	  // timing parameters
33	  localparam time CyclTime = 10ns;
34	  localparam time ApplTime =  2ns;
35	  localparam time TestTime =  8ns;
36	  // AXI configuration
37	  localparam int unsigned TbAxiStrbWidthSlv =  TbAxiDataWidthSlv / 32'd8;
38	  localparam int unsigned TbAxiStrbWidthMst =  TbAxiDataWidthMst / 32'd8;
39	  // Type definitions
