48	  `AXI_LITE_TYPEDEF_W_CHAN_T(w_chan_lite_slv_t, data_slv_t, strb_slv_t)
49	  `AXI_LITE_TYPEDEF_W_CHAN_T(w_chan_lite_mst_t, data_mst_t, strb_mst_t)
50	  `AXI_LITE_TYPEDEF_B_CHAN_T(b_chan_lite_t)
51	
52	  `AXI_LITE_TYPEDEF_AR_CHAN_T(ar_chan_lite_t, addr_t)
53	  `AXI_LITE_TYPEDEF_R_CHAN_T(r_chan_lite_slv_t, data_slv_t)
54	  `AXI_LITE_TYPEDEF_R_CHAN_T(r_chan_lite_mst_t, data_mst_t)
55	
56	
57	  `AXI_LITE_TYPEDEF_REQ_T(req_lite_slv_t, aw_chan_lite_t, w_chan_lite_slv_t, ar_chan_lite_t)
58	  `AXI_LITE_TYPEDEF_RESP_T(res_lite_slv_t, b_chan_lite_t, r_chan_lite_slv_t)
59	
60	  `AXI_LITE_TYPEDEF_REQ_T(req_lite_mst_t, aw_chan_lite_t, w_chan_lite_mst_t, ar_chan_lite_t)
61	  `AXI_LITE_TYPEDEF_RESP_T(res_lite_mst_t, b_chan_lite_t, r_chan_lite_mst_t)
62	
63	
64	  typedef axi_test::axi_lite_rand_master #(
65	    // AXI interface parameters
66	    .AW ( TbAxiAddrWidth    ),
67	    .DW ( TbAxiDataWidthSlv ),
68	    // Stimuli application and test time
69	    .TA ( ApplTime          ),
70	    .TT ( TestTime          ),
71	    .MIN_ADDR (  0          ),
72	    .MAX_ADDR ( '1          ),
73	    .MAX_READ_TXNS  ( 100   ),
74	    .MAX_WRITE_TXNS ( 100   )
75	  ) rand_lite_master_t;
76	  typedef axi_test::axi_lite_rand_slave #(
77	    // AXI interface parameters
78	    .AW ( TbAxiAddrWidth    ),
79	    .DW ( TbAxiDataWidthMst ),
80	    // Stimuli application and test time
81	    .TA ( ApplTime          ),
82	    .TT ( TestTime          )
83	  ) rand_lite_slave_t;
84	
85	  // -------------
86	  // DUT signals
87	  // -------------
88	  logic clk;
89	  // DUT signals
90	  logic rst_n;
91	  logic end_of_sim;
92	
93	  // master structs
94	  req_lite_slv_t  master_req;
95	  res_lite_slv_t master_res;
96	
97	  // slave structs
98	  req_lite_mst_t  slave_req;
99	  res_lite_mst_t slave_res;
100	
101	  // -------------------------------
102	  // AXI Interfaces
103	  // -------------------------------
104	  AXI_LITE #(
105	    .AXI_ADDR_WIDTH ( TbAxiAddrWidth    ),
106	    .AXI_DATA_WIDTH ( TbAxiDataWidthSlv )
107	  ) master ();
108	  AXI_LITE_DV #(
109	    .AXI_ADDR_WIDTH ( TbAxiAddrWidth    ),
110	    .AXI_DATA_WIDTH ( TbAxiDataWidthSlv )
111	  ) master_dv (clk);
112	  `AXI_LITE_ASSIGN(master, master_dv)
113	  `AXI_LITE_ASSIGN_TO_REQ(master_req, master)
114	  `AXI_LITE_ASSIGN_TO_RESP(master_res, master)
115	
116	  AXI_LITE #(
117	    .AXI_ADDR_WIDTH ( TbAxiAddrWidth    ),
118	    .AXI_DATA_WIDTH ( TbAxiDataWidthMst )
119	  ) slave ();
120	  AXI_LITE_DV #(
121	    .AXI_ADDR_WIDTH ( TbAxiAddrWidth    ),
122	    .AXI_DATA_WIDTH ( TbAxiDataWidthMst )
123	  ) slave_dv (clk);
124	  `AXI_LITE_ASSIGN(slave_dv, slave)
125	  `AXI_LITE_ASSIGN_TO_REQ(slave_req, slave)
126	  `AXI_LITE_ASSIGN_TO_RESP(slave_res, slave)
127	  // -------------------------------
128	  // AXI Rand Masters and Slaves
129	  // -------------------------------
130	  // Masters control simulation run time
131	  initial begin : proc_generate_traffic
132	    automatic rand_lite_master_t lite_axi_master = new ( master_dv, "MST_0");
133	    automatic data_slv_t      data = '0;
134	    automatic axi_pkg::resp_t resp = '0;
135	    end_of_sim <= 1'b0;
136	    lite_axi_master.reset();
137	    @(posedge rst_n);
138	    lite_axi_master.write(32'h0000_1100, axi_pkg::prot_t'('0), data_slv_t'(64'hDEADBEEFDEADBEEF),
139	        strb_slv_t'(8'hFF), resp);
140	    lite_axi_master.read(32'h0000_e100, axi_pkg::prot_t'('0), data, resp);
141	    lite_axi_master.run(NumReads, NumWrites);
142	    end_of_sim <= 1'b1;
143	  end
144	
145	  initial begin : proc_recieve_traffic
146	    automatic rand_lite_slave_t lite_axi_slave = new( slave_dv , "SLV_0");
147	    lite_axi_slave.reset();
148	    @(posedge rst_n);
149	    lite_axi_slave.run();
150	  end
151	
152	  // FIFOs for sampling the channels
153	  // Slave Port
154	  aw_chan_lite_t    fifo_slv_aw[$];
155	  w_chan_lite_slv_t fifo_slv_w[$];
156	  b_chan_lite_t     fifo_slv_b[$];
157	  ar_chan_lite_t    fifo_slv_ar[$];
158	  r_chan_lite_slv_t fifo_slv_r[$];
159	
160	  aw_chan_lite_t    fifo_mst_aw[$];
161	  w_chan_lite_mst_t fifo_mst_w[$];
162	  b_chan_lite_t     fifo_mst_b[$];
163	  ar_chan_lite_t    fifo_mst_ar[$];
164	  r_chan_lite_mst_t fifo_mst_r[$];
165	  // Sampling processes
166	  initial begin : proc_sample
167	    forever begin
168	      @(posedge clk);
169	      #TestTime;
170	      if (rst_n) begin
171	        if (master_req.aw_valid && master_res.aw_ready) begin
172	          fifo_slv_aw.push_back(master_req.aw);
173	        end
174	        if (master_req.w_valid && master_res.w_ready) begin
175	          fifo_slv_w.push_back(master_req.w);
176	        end
177	        if (master_res.b_valid && master_req.b_ready) begin
178	          fifo_slv_b.push_back(master_res.b);
179	        end
180	        if (master_req.ar_valid && master_res.ar_ready) begin
181	          fifo_slv_ar.push_back(master_req.ar);
182	        end
183	        if (master_res.r_valid && master_req.r_ready) begin
184	          fifo_slv_r.push_back(master_res.r);
185	        end
186	        if (slave_req.aw_valid && slave_res.aw_ready) begin
187	          fifo_mst_aw.push_back(slave_req.aw);
188	        end
189	        if (slave_req.w_valid && slave_res.w_ready) begin
190	          fifo_mst_w.push_back(slave_req.w);
191	        end
192	        if (slave_res.b_valid && slave_req.b_ready) begin
193	          fifo_mst_b.push_back(slave_res.b);
194	        end
195	        if (slave_req.ar_valid && slave_res.ar_ready) begin
196	          fifo_mst_ar.push_back(slave_req.ar);
197	        end
198	        if (slave_res.r_valid && slave_req.r_ready) begin
199	          fifo_mst_r.push_back(slave_res.r);
200	        end
201	      end
202	    end
203	  end
204	
205	  if (TbAxiDataWidthMst < TbAxiDataWidthSlv) begin : gen_down_gm
206	    localparam int unsigned DataDivFactor = TbAxiDataWidthSlv / TbAxiDataWidthMst;
207	    localparam int unsigned AddrShift     = $clog2(TbAxiDataWidthMst/8);
208	    localparam int unsigned SelWidth      = $clog2(DataDivFactor);
209	    typedef logic [SelWidth-1:0] sel_t;
210	    aw_chan_lite_t    fifo_exp_aw[$];
211	    w_chan_lite_mst_t fifo_exp_w[$];
212	    ar_chan_lite_t    fifo_exp_ar[$];
213	
214	    // Golden model for down conversion
215	    initial begin : proc_write_exp_gen
216	      automatic aw_chan_lite_t    chan_aw, exp_aw;
217	      automatic w_chan_lite_slv_t chan_w;
218	      automatic w_chan_lite_mst_t exp_w;
219	      automatic int unsigned      num_vectors; // Number of expected transactions generated
220	      automatic addr_t            exp_addr;
221	      automatic sel_t             w_sel;
222	
223	      forever begin
224	        wait((fifo_slv_aw.size() > 0) && (fifo_slv_w.size() > 0));
225	        chan_aw  = fifo_slv_aw.pop_front();
226	        chan_w   = fifo_slv_w.pop_front();
227	        exp_addr = chan_aw.addr;
228	        exp_addr = exp_addr >> (AddrShift + SelWidth);
229	        for (int unsigned i = 0; i < DataDivFactor; i++) begin
230	          // Generate expected AW vector
231	          exp_aw = aw_chan_lite_t'{
232	            addr: ((exp_addr << SelWidth) + i) << AddrShift,
233	            prot: chan_aw.prot
234	          };
235	          fifo_exp_aw.push_back(exp_aw);
236	          // Generate expected W vector
237	          exp_w    = w_chan_lite_mst_t'{
238	            data: chan_w.data[i*TbAxiDataWidthMst+:TbAxiDataWidthMst],
239	            strb: chan_w.strb[i*TbAxiStrbWidthMst+:TbAxiStrbWidthMst]
240	          };
241	          fifo_exp_w.push_back(exp_w);
242	        end
243	      end
244	    end
245	
246	    initial begin : proc_aw_exp_check
247	      automatic aw_chan_lite_t chan_aw, exp_aw;
248	      forever begin
249	        wait((fifo_exp_aw.size() > 0) && (fifo_mst_aw.size() > 0));
250	        chan_aw = fifo_mst_aw.pop_front();
251	        exp_aw  = fifo_exp_aw.pop_front();
252	        assert (chan_aw.addr == exp_aw.addr) else
253	            $error("Master port> AW.addr is not expected: EXP: %h ACT:%h",
254	                exp_aw.addr, chan_aw.addr);
255	        assert (chan_aw.prot == exp_aw.prot) else
256	            $error("Master port> AW.prot is not expected: EXP: %h ACT:%h",
257	                   exp_aw.prot, chan_aw.prot);
258	      end
259	    end
260	    initial begin : proc_w_exp_check
261	      automatic w_chan_lite_mst_t chan_w, exp_w;
262	      forever begin
263	        wait((fifo_exp_w.size() > 0) && (fifo_mst_w.size() > 0));
264	        chan_w = fifo_mst_w.pop_front();
265	        exp_w  = fifo_exp_w.pop_front();
266	        assert (chan_w.data == exp_w.data) else
267	            $error("Master port> W.data is not expected: EXP: %h ACT:%h",
268	                exp_w.data, chan_w.data);
269	        assert (chan_w.strb == exp_w.strb) else
270	            $error("Master port> W.strb is not expected: EXP: %h ACT:%h",
271	                   exp_w.strb, chan_w.strb);
272	      end
273	    end
274	    initial begin : proc_b_exp_check
275	      automatic b_chan_lite_t exp_b, act_b;
276	      forever begin
277	        // wait until there are this many B responses in the sampling FIFO
278	        wait(fifo_mst_b.size() >= DataDivFactor);
279	        exp_b = axi_pkg::RESP_OKAY;
280	        for (int unsigned i = 0; i < DataDivFactor; i++) begin
281	          act_b = fifo_mst_b.pop_front();
282	          exp_b = exp_b | act_b;
283	        end
284	        // Do the check
285	        wait(fifo_slv_b.size() > 0);
286	        act_b = fifo_slv_b.pop_front();
287	        assert(exp_b.resp == act_b.resp) else
288	            $error("Slave port> B.resp is not expected: EXP: %h ACT: %h", exp_b.resp, act_b.resp);
289	      end
290	    end
291	    initial begin : proc_ar_exp_check
292	      automatic ar_chan_lite_t chan_ar, exp_ar;
293	      forever begin
294	        wait((fifo_exp_ar.size() > 0) && (fifo_mst_ar.size() > 0));
295	        chan_ar = fifo_mst_ar.pop_front();
296	        exp_ar  = fifo_exp_ar.pop_front();
297	        assert (chan_ar.addr == exp_ar.addr) else
298	            $error("Master port> AR.addr is not expected: EXP: %h ACT:%h",
299	                exp_ar.addr, chan_ar.addr);
300	        assert (chan_ar.prot == exp_ar.prot) else
301	            $error("Master port> AR.prot is not expected: EXP: %h ACT:%h",
302	                   exp_ar.prot, chan_ar.prot);
303	      end
304	    end
305	    initial begin : proc_r_exp_check
306	      automatic r_chan_lite_slv_t exp_r, act_r;
307	      automatic r_chan_lite_mst_t mst_r;
308	      forever begin
309	        wait(fifo_slv_r.size() > 0);
310	        act_r = fifo_slv_r.pop_front();
311	        exp_r = r_chan_lite_slv_t'{default: '0};
312	        // Build the expected R response from the master port fifo.
313	        for (int unsigned i = 0; i < DataDivFactor; i++) begin
314	          mst_r = fifo_mst_r.pop_front();
315	          exp_r.data[i*TbAxiDataWidthMst+:TbAxiDataWidthMst] = mst_r.data;
316	          exp_r.resp = exp_r.resp | mst_r.resp;
317	        end
318	        assert (act_r.data == exp_r.data) else
319	            $error("Slave port> R.data is not expected: EXP: %h ACT:%h",
320	                exp_r.data, act_r.data);
321	        assert (act_r.resp == exp_r.resp) else
322	            $error("Slave port> R.resp is not expected: EXP: %h ACT:%h",
323	                   exp_r.resp, act_r.resp);
324	      end
325	    end
326	  end else if (TbAxiDataWidthMst == TbAxiDataWidthSlv) begin
327	    initial begin : proc_passthrough_check
328	      forever begin
329	        @(posedge clk);
330	        #TestTime;
331	        if (rst_n) begin
332	          assert (master_req == slave_req);
333	          assert (master_res == slave_res);
334	        end
335	      end
336	    end
337	  end else begin
338	    // Upsizer
339	    localparam int unsigned DataMultFactor = TbAxiDataWidthMst / TbAxiDataWidthSlv;
340	    localparam int unsigned AddrShift      = $clog2(TbAxiDataWidthSlv/8);
341	    localparam int unsigned SelWidth       = $clog2(DataMultFactor);
342	    typedef logic [SelWidth-1:0] sel_t;
343	
344	    sel_t             fifo_exp_r_offs[$];
345	
346	    initial begin : proc_aw_w_check
347	      automatic aw_chan_lite_t    mst_aw_chan, slv_aw_chan;
348	      automatic w_chan_lite_slv_t slv_w_chan;
349	      automatic w_chan_lite_mst_t mst_w_chan;
350	      automatic addr_t            exp_addr;
351	      automatic sel_t             w_sel;
352	      automatic logic [TbAxiDataWidthMst/8-1:0] slv_w_strb_concat;
353	
354	      forever begin
355	        wait((fifo_slv_aw.size() > 0) && (fifo_mst_aw.size() > 0) && (fifo_slv_w.size() > 0) && (fifo_mst_w.size() > 0));
356	        slv_aw_chan = fifo_slv_aw.pop_front();
357	        slv_w_chan  = fifo_slv_w.pop_front();
358	        mst_aw_chan = fifo_mst_aw.pop_front();
359	        mst_w_chan  = fifo_mst_w.pop_front();
360	        w_sel       = slv_aw_chan.addr[AddrShift+SelWidth-1:AddrShift];
361	
362	        assert (slv_aw_chan == mst_aw_chan) else $error("Master port> AW is not expected: EXP: %h ACT: %h",
363	            slv_aw_chan, mst_aw_chan);
364	        assert (slv_w_chan.data == mst_w_chan.data[TbAxiDataWidthSlv-1:0]) else $error("Master port> W.data is not expected: EXP: %h ACT: %h",
365	            slv_w_chan.data, mst_w_chan.data);
366	
367	        slv_w_strb_concat = slv_w_chan.strb << (w_sel*TbAxiDataWidthSlv/8);
368	        assert (slv_w_strb_concat == mst_w_chan.strb) else $error("Master port> W.strb is not expected: EXP: %h ACT: %h",
369	            slv_w_chan.strb, mst_w_chan.strb);
370	      end
371	    end
372	
373	    initial begin : proc_b_check
374	      automatic b_chan_lite_t b_act, b_exp;
375	      forever begin
376	        wait((fifo_slv_b.size() > 0) && (fifo_mst_b.size() > 0));
377	        b_act = fifo_slv_b.pop_front();
378	        b_exp = fifo_mst_b.pop_front();
379	        assert (b_act == b_exp) else  $error("Slave port> B.resp is not expected: EXP: %h ACT:%h",
380	            b_exp.resp, b_act.resp);
381	      end
382	    end
383	
384	    initial begin : proc_ar_check
385	      automatic ar_chan_lite_t mst_ar_chan, slv_ar_chan;
386	      automatic sel_t r_sel;
387	
388	      forever begin
389	        wait((fifo_slv_ar.size() > 0) && (fifo_mst_ar.size() > 0));
390	        slv_ar_chan = fifo_slv_ar.pop_front();
391	        mst_ar_chan = fifo_mst_ar.pop_front();
392	        r_sel = slv_ar_chan.addr[AddrShift+SelWidth-1:AddrShift];
393	        fifo_exp_r_offs.push_back(r_sel);
394	
395	        assert (slv_ar_chan == mst_ar_chan) else $error("Master port> AR is not expected: EXP: %h ACT: %h",
396	          slv_ar_chan, mst_ar_chan);
397	      end
398	    end
399	
400	    initial begin : proc_r_check
401	      automatic r_chan_lite_slv_t slv_r_chan;
402	      automatic r_chan_lite_mst_t mst_r_chan;
403	      automatic sel_t             r_sel;
404	
405	      forever begin
406	        wait((fifo_slv_r.size() > 0) && (fifo_mst_r.size() > 0) && (fifo_exp_r_offs.size() > 0));
407	        slv_r_chan = fifo_slv_r.pop_front();
408	        mst_r_chan = fifo_mst_r.pop_front();
409	        r_sel      = fifo_exp_r_offs.pop_front();
410	
411	        assert (slv_r_chan.resp == mst_r_chan.resp) else $error("Slave port> R.resp is not expected: EXP: %h, ACT: %h",
412	          mst_r_chan.resp, slv_r_chan.resp);
413	        assert (slv_r_chan.data == data_slv_t'(mst_r_chan.data >> (r_sel*TbAxiDataWidthSlv))) else $error("Slave port> R.data is not expected: EXP: %h, ACT: %h",
414	          mst_r_chan.data, slv_r_chan.data);
415	      end
416	    end
417	
418	  end
419	
420	
421	  initial begin : proc_stop_sim
422	    wait (end_of_sim);
423	    repeat (1000) @(posedge clk);
424	    $display("Simulation stopped as all Masters transferred their data, Success.",);
425	    $stop();
426	  end
427	
428	  //-----------------------------------
429	  // Clock generator
430	  //-----------------------------------
431	  clk_rst_gen #(
432	    .ClkPeriod   ( CyclTime ),
433	    .RstClkCycles( 5        )
434	  ) i_clk_gen (
435	    .clk_o (clk),
436	    .rst_no(rst_n)
437	  );
438	
439	  //-----------------------------------
440	  // DUT
441	  //-----------------------------------
442	  axi_lite_dw_converter_intf #(
443	    .AXI_ADDR_WIDTH          ( TbAxiAddrWidth    ),
444	    .AXI_SLV_PORT_DATA_WIDTH ( TbAxiDataWidthSlv ),
445	    .AXI_MST_PORT_DATA_WIDTH ( TbAxiDataWidthMst )
446	  ) i_axi_lite_dw_downsizer_dut (
447	    .clk_i  ( clk    ),
448	    .rst_ni ( rst_n  ),
449	    .slv    ( master ),
450	    .mst    ( slave  )
451	  );
452	endmodule
453

